#include<bits/stdc++.h>
using namespace std;
int main() {
	int a[100001],n,i,maxa=0,j=1,cnt=1;
	cin>>n;
	for(int i=0;i<n;i++){
		for(int j=1;j<=n;j++){
			if(i*n+j<10){
				cout<<0;
			}cout<<i*n+j;
		}cout<<endl;
	}cout<<endl;
    for(int i=n;i>0;i--){
		for(int j=1;j<i;j++){
			cout<<"  ";
		}
		for(int j=i;j<=n;j++){
			if(cnt<10){
				cout<<"0"<<cnt;
			}else{
				cout<<cnt;
			}cnt++;
		}cout<<endl;
	}
}
